BEGIN IF (OBJECT_ID('HistoryObjectsUpsert', 'P') IS NOT NULL) BEGIN DROP PROCEDURE [HistoryObjectsUpsert]; END;
IF (TYPE_ID('HistoryObjectTableType') IS NOT NULL) BEGIN DROP TYPE [HistoryObjectTableType]; END;
CREATE TYPE [HistoryObjectTableType] AS TABLE ( [Id] BIGINT, [Uid] UNIQUEIDENTIFIER, [Object] NVARCHAR(70), [Model] NVARCHAR(MAX), [ActionDate] DATETIME, [ActionTypeUid] UNIQUEIDENTIFIER, [CreationAuthor] BIGINT, [EventArgsUid] UNIQUEIDENTIFIER, [SessionUid] UNIQUEIDENTIFIER, [UnitOfWorkUid] UNIQUEIDENTIFIER, [IsRelatedEvent] BIT); END;


          BEGIN
