            BEGIN
              DROP PROCEDURE [HistoryUpdateQueueItemsUpsert];
            END;

	          IF (TYPE_ID('HistoryUpdateQueueItemTableType') IS NOT NULL)
            BEGIN
              DROP TYPE [HistoryUpdateQueueItemTableType];
            END;

            CREATE TYPE [HistoryUpdateQueueItemTableType]
            AS TABLE (
              [Id] BIGINT,
              [ObjectId] BIGINT,
              [ObjectTypeUid] UNIQUEIDENTIFIER,
              [DeleteRelated] BIT,
              [CreationDate] DATETIME,
              [NextUpdateDate] DATETIME);
          END;

procedure.text:

          CREATE PROCEDURE [UpdateCachedHistoryObjects]
	          @tableName NVARCHAR(100),
            @oldObject NVARCHAR(70),
            @newObject NVARCHAR(70)
          AS
          BEGIN
            DECLARE @query NVARCHAR(250) = N'UPDATE ' + @tableName + ' SET [Object] = ''' + @newObject + ''' WHERE [Object] = ''' + @oldObject + ''';';
	          EXECUTE sp_executesql @query;
	          UPDATE [HistoryObjectObserver] SET [Parent] = @newObject WHERE [Parent] = @oldObject;
	          UPDATE [HistoryObjectObserver] SET [Child] = @newObject WHERE [Child] = @oldObject;
          END


CREATE PROCEDURE [HistoryObjectObserversUpsert]
  @tvp [HistoryObjectObserverTableType] READONLY
AS
BEGIN
  SET NOCOUNT ON;

  BEGIN TRANSACTION;

  INSERT INTO [HistoryObjectObserver] ([Parent], [Child])
  SELECT [Parent], [Child] FROM @tvp AS tvp
  WHERE NOT EXISTS (SELECT 1 FROM [HistoryObjectObserver] WITH (UPDLOCK, SERIALIZABLE) WHERE [Parent] = tvp.[Parent] AND [Child] = tvp.[Child]);

  COMMIT TRANSACTION;
END


          CREATE PROCEDURE [HistoryObjectsUpsert]
	          @tableName NVARCHAR(100),
	          @tvp [HistoryObjectTableType] READONLY
          AS
          BEGIN
            DECLARE @sqlCommand nvarchar(max);

            SET NOCOUNT ON;

            BEGIN TRANSACTION;

            set @sqlCommand = 'INSERT INTO ' + @tableName + ' ([Id], [Uid], [Object], [Model], [ActionDate], [ActionTypeUid], [CreationAuthor], [EventArgsUid], [SessionUid], [UnitOfWorkUid], [IsRelatedEvent])
            SELECT [Id], [Uid], [Object], [Model], [ActionDate], [ActionTypeUid], [CreationAuthor], [EventArgsUid], [SessionUid], [UnitOfWorkUid], [IsRelatedEvent] FROM @tvp AS tvp
            WHERE NOT EXISTS (SELECT 1 FROM ' + @tableName + ' WITH (UPDLOCK, SERIALIZABLE) WHERE [Id] = tvp.[Id]);';

            EXECUTE sp_executesql @sqlCommand, N'@tvp [HistoryObjectTableType] READONLY', @tvp = @tvp

            COMMIT TRANSACTION;
          END


CREATE PROCEDURE [HistoryUpdateQueueItemsUpsert]
  @tvp [HistoryUpdateQueueItemTableType] READONLY
AS
BEGIN
  SET NOCOUNT ON;

  BEGIN TRANSACTION;

  INSERT INTO [HistoryUpdateQueueItem] ([Id], [ObjectId], [ObjectTypeUid], [LastActionDate], [DeleteRelated], [CreationDate], [Attempt], [LastUpdateDate], [NextUpdateDate], [ServerConnectionUid])
  SELECT [Id], [ObjectId], [ObjectTypeUid], NULL, [DeleteRelated], [CreationDate], 0, NULL, [NextUpdateDate], NULL FROM @tvp AS tvp
  WHERE NOT EXISTS (SELECT 1 FROM [HistoryUpdateQueueItem] WITH (UPDLOCK, SERIALIZABLE) WHERE [ObjectId] = tvp.[ObjectId] AND [ObjectTypeUid] = tvp.[ObjectTypeUid]);

  COMMIT TRANSACTION;
END
